#include <bits/stdc++.h>
using namespace std;
int a[1025][1025];
int main(){
	//freopen("beautiful.out","w",stdout);
	int n;
	scanf("%d",&n);
	for(int i=1;i<=1<<n;i++){
		for(int j=i+1;j<=1<<n;j++)
			printf(" ");
		for(int j=1;j<=i;j++)
			a[i][j]=(j==1 || j==i?1:a[i-1][j-1]^a[i-1][j]);
		if(i%2==1)
			for(int j=1;j<=i;j++)
				if(a[i][j])
					printf("/\\");
				else
					printf("  ");
		else
			for(int j=1;j<=i;j+=2)
				if(a[i][j])
					printf("/__\\");
				else
					printf("    ");
		printf("\n");
	}
	return 0;
}
